              posts.forEach(post => {
                const key = `${post.page}-${post.scheduledFor}`;
                if (!grouped[key]) {
                  grouped[key] = { ...post, platforms: [post.platform] };
                } else {
                  grouped[key].platforms.push(post.platform);
                }
              });
              return Object.values(grouped).sort((a, b) => a.scheduledFor.localeCompare(b.scheduledFor));
