                  // For now, log what we would send - you'll need to map handles to Late account IDs
                  console.log('Would schedule:', {
                    handle: post.handle,
                    platform,
                    caption: fullCaption,
                    videoUrl: post.videoUrl,
                    scheduledFor
                  });

